// src/pages/WalletPage.jsx
import React, { useState, useEffect, useCallback } from 'react';
import { useTranslation } from 'react-i18next';
import { useNavigate } from 'react-router-dom';
import { 
  Wallet, Plus, ArrowDownLeft, ArrowUpRight, Clock, 
  CreditCard, DollarSign, AlertCircle, Loader2 
} from 'lucide-react';
import '../../styles/WalletPage.css';

// Optional: Extract reusable components for better maintainability
// import BalanceCard from '../../components/wallet/BalanceCard';
// import TransactionList from '../../components/wallet/TransactionList';

export default function WalletPage() {
  const { t } = useTranslation();
  const navigate = useNavigate();
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState(null);
  
  // Wallet state
  const [walletData, setWalletData] = useState({
    balance: 0,
    currency: 'USD',
    verified: true,
    transactions: []
  });

  // Fetch wallet data from API
  const fetchWalletData = useCallback(async () => {
    try {
      setLoading(true);
      setError(null);
      
      // TODO: Replace with actual API call
      // const res = await api.get('/wallet');
      await new Promise(res => setTimeout(res, 800)); // Simulate network delay
      
      setWalletData({
        balance: 142.75,
        currency: 'USD',
        verified: true,
        transactions: [
          { 
            id: 1, 
            type: 'deposit', 
            amount: 50.00, 
            date: '2026-04-01T10:30:00Z', 
            description: t('wallet.transactions.topupCard'), 
            status: 'completed',
            reference: 'TXN-2026-001'
          },
          { 
            id: 2, 
            type: 'purchase', 
            amount: -24.99, 
            date: '2026-03-28T14:22:00Z', 
            description: `${t('wallet.transactions.order')} #QP-8821`, 
            status: 'completed',
            reference: 'ORD-QP-8821'
          },
          { 
            id: 3, 
            type: 'refund', 
            amount: 15.50, 
            date: '2026-03-25T09:15:00Z', 
            description: `${t('wallet.transactions.refund')} #QP-7740`, 
            status: 'pending',
            reference: 'REF-QP-7740'
          },
        ]
      });
    } catch (err) {
      console.error('Failed to load wallet data:', err);
      setError(t('wallet.errors.loadFailed'));
    } finally {
      setLoading(false);
    }
  }, [t]);

  useEffect(() => {
    fetchWalletData();
  }, [fetchWalletData]);

  // Navigation handlers
  const handleAddFunds = useCallback(() => {
    navigate('/wallet/add-funds', { 
      state: { 
        currentBalance: walletData.balance,
        currency: walletData.currency,
        returnUrl: '/wallet'
      } 
    });
  }, [navigate, walletData]);

  const handleWithdraw = useCallback(() => {
    navigate('/wallet/withdraw', { 
      state: { 
        availableBalance: walletData.balance,
        currency: walletData.currency,
        returnUrl: '/wallet'
      } 
    });
  }, [navigate, walletData]);

  const handleViewAllTransactions = useCallback(() => {
    navigate('/wallet/transactions');
  }, [navigate]);

  const handleRetry = useCallback(() => {
    fetchWalletData();
  }, [fetchWalletData]);

  // Helper functions
  const getTransactionIcon = useCallback((type) => {
    const iconProps = { size: 18 };
    switch(type) {
      case 'deposit': return <ArrowDownLeft {...iconProps} />;
      case 'purchase': return <CreditCard {...iconProps} />;
      case 'refund': return <ArrowUpRight {...iconProps} />;
      case 'withdrawal': return <ArrowDownLeft {...iconProps} />;
      default: return <Clock {...iconProps} />;
    }
  }, []);

  const getAmountColor = useCallback((amount) => 
    amount >= 0 ? 'amount-positive' : 'amount-negative'
  , []);

  const getStatusConfig = useCallback((status) => {
    const configs = {
      completed: { icon: '✓', className: 'tx-completed', label: t('wallet.status.completed') },
      pending: { icon: '⏳', className: 'tx-pending', label: t('wallet.status.pending') },
      failed: { icon: '✕', className: 'tx-failed', label: t('wallet.status.failed') }
    };
    return configs[status] || configs.pending;
  }, [t]);

  const formatDate = useCallback((dateString) => {
    return new Date(dateString).toLocaleDateString(undefined, {
      year: 'numeric',
      month: 'short',
      day: 'numeric',
      hour: '2-digit',
      minute: '2-digit'
    });
  }, []);

  // Loading skeleton
  if (loading) {
    return (
      <div className="page wallet-page">
        <div className="page-header">
          <Wallet size={26} className="header-icon" />
          <h1>{t('nav.wallet')}</h1>
        </div>
        <div className="wallet-skeleton">
          <div className="skeleton skeleton-balance-card" />
          <div className="skeleton skeleton-section-header" />
          <div className="skeleton skeleton-transaction-list">
            {[1, 2, 3].map(i => (
              <div key={i} className="skeleton skeleton-transaction-item" />
            ))}
          </div>
        </div>
      </div>
    );
  }

  // Error state
  if (error) {
    return (
      <div className="page wallet-page">
        <div className="page-header">
          <Wallet size={26} className="header-icon" />
          <h1>{t('nav.wallet')}</h1>
        </div>
        <div className="error-state">
          <AlertCircle size={48} className="error-icon" />
          <h3>{t('wallet.errors.title')}</h3>
          <p>{error}</p>
          <button 
            className="btn btn-primary" 
            onClick={handleRetry}
            disabled={loading}
          >
            {loading ? <Loader2 size={16} className="animate-spin" /> : null}
            {t('common.retry')}
          </button>
        </div>
      </div>
    );
  }

  return (
    <div className="page wallet-page">
      {/* Page Header */}
      <div className="page-header">
        <Wallet size={26} className="header-icon" />
        <h1>{t('nav.wallet')}</h1>
      </div>

      {/* Balance Card */}
      <div className="wallet-balance-card">
        <div className="balance-header">
          <span className="balance-label">{t('wallet.availableBalance')}</span>
          {walletData.verified && (
            <span className="wallet-badge wallet-verified">
              ✓ {t('wallet.verified')}
            </span>
          )}
        </div>
        
        <div className="balance-amount">
          <DollarSign size={28} className="currency-icon" />
          <span className="balance-value">
            {walletData.balance.toLocaleString(undefined, { 
              minimumFractionDigits: 2, 
              maximumFractionDigits: 2 
            })}
          </span>
          <span className="currency-code">{walletData.currency}</span>
        </div>
        
        <div className="balance-actions">
          <button 
            className="btn btn-wallet btn-primary" 
            onClick={handleAddFunds}
            aria-label={t('wallet.addFunds')}
          >
            <Plus size={16} /> 
            <span>{t('wallet.addFunds')}</span>
          </button>
          <button 
            className="btn btn-wallet btn-outline" 
            onClick={handleWithdraw}
            aria-label={t('wallet.withdraw')}
          >
            <ArrowDownLeft size={16} /> 
            <span>{t('wallet.withdraw')}</span>
          </button>
        </div>
      </div>

      {/* Transaction History Section */}
      <div className="wallet-history-section">
        <div className="section-header">
          <h2>{t('wallet.transactionHistory')}</h2>
          <button 
            className="btn btn-text" 
            onClick={handleViewAllTransactions}
            aria-label={t('wallet.viewAll')}
          >
            {t('wallet.viewAll')} <ArrowUpRight size={14} />
          </button>
        </div>

        <div className="transactions-list">
          {walletData.transactions.length > 0 ? (
            walletData.transactions.map((tx) => {
              const statusConfig = getStatusConfig(tx.status);
              return (
                <div 
                  key={tx.id} 
                  className="transaction-item"
                  role="listitem"
                >
                  <div className={`tx-icon tx-${tx.type}`}>
                    {getTransactionIcon(tx.type)}
                  </div>
                  
                  <div className="tx-details">
                    <p className="tx-description">{tx.description}</p>
                    <p className="tx-date">{formatDate(tx.date)}</p>
                    {tx.reference && (
                      <p className="tx-reference">Ref: {tx.reference}</p>
                    )}
                  </div>
                  
                  <div className="tx-amount-wrapper">
                    <span className={`tx-amount ${getAmountColor(tx.amount)}`}>
                      {tx.amount >= 0 ? '+' : '-'}
                      {Math.abs(tx.amount).toFixed(2)}
                      <span className="tx-currency">{walletData.currency}</span>
                    </span>
                    <span className={`tx-status ${statusConfig.className}`} title={statusConfig.label}>
                      {statusConfig.icon}
                    </span>
                  </div>
                </div>
              );
            })
          ) : (
            <div className="empty-state">
              <Wallet size={48} className="empty-icon" />
              <h3>{t('wallet.noTransactions.title')}</h3>
              <p>{t('wallet.noTransactions.description')}</p>
              <button 
                className="btn btn-primary btn-sm" 
                onClick={handleAddFunds}
              >
                {t('wallet.startShopping')}
              </button>
            </div>
          )}
        </div>
      </div>

      {/* Quick Actions Footer (Optional) */}
      <div className="wallet-quick-actions">
        <button className="quick-action-btn" onClick={handleAddFunds}>
          <Plus size={20} />
          <span>{t('wallet.quickActions.addFunds')}</span>
        </button>
        <button className="quick-action-btn" onClick={handleWithdraw}>
          <ArrowDownLeft size={20} />
          <span>{t('wallet.quickActions.withdraw')}</span>
        </button>
        <button className="quick-action-btn" onClick={handleViewAllTransactions}>
          <Clock size={20} />
          <span>{t('wallet.quickActions.history')}</span>
        </button>
      </div>
    </div>
  );
}
